import socket
import threading
import json
import base64
import os

client_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)

nickname = input("Enter your nickname: ")
client_socket.sendto(json.dumps({"command": "join", "content": ("JOINED: " + nickname)}).encode(), ('localhost', 12345))

def receive_messages():
    while True:
        data, addr = client_socket.recvfrom(65535)
        message = json.loads(data)

        if message.get("command") == "file":
            file_content = base64.b64decode(message["content"])
            with open(message["filename"], "wb") as file:
                file.write(file_content)
            print(f"{message['from']}: {message['filename']} received.")

        else:
            print(f"{message['from']}: {message['content']}")

def send_messages():
    while True:
        message = input()

        if message.startswith('/msg '):
            parts = message.split(' ', 2)
            recipient = input("Enter the recipient's address 'ip:port': ").split(':')
            formatted_message = {"command": "private", "recipient": [recipient[0], int(recipient[1])], "content": parts[1]}
            client_socket.sendto(json.dumps(formatted_message).encode(), ('localhost', 12345))

        elif message.startswith('/file '):
            filepath = message.split(' ', 1)[1]
            recipient = input("Enter the recipient's address 'ip:port': ").split(':')

            if os.path.isfile(filepath):
                with open(filepath, 'rb') as file:
                    file_content = file.read()
                encoded_content = base64.b64encode(file_content).decode()

                formatted_message = {"command": "file", "recipient": [recipient[0], int(recipient[1])], "filename": os.path.basename(filepath), "content": encoded_content}
                client_socket.sendto(json.dumps(formatted_message).encode(), ('localhost', 12345))

            else:
                print("File does not exist.")
        else:
            client_socket.sendto(json.dumps({"command": "message", "content": (nickname + ": " + message)}).encode(), ('localhost', 12345))

receive_thread = threading.Thread(target=receive_messages)
send_thread = threading.Thread(target=send_messages)

receive_thread.start()
send_thread.start()
